12345678910111213141516171819202122232425262728293031323334&lt;?phpfunction steem_per_mvests() &#123; $url = &apos;https://api.steemit.com&apos;; $data = &apos;&#123;&quot;jsonrpc&quot;:&quot;2.0&quot;, &quot;method&quot;:&quot;database_api.get_dynamic_global_properties&quot;, &quot;id&quot;:1&#125;&apos;; $options = array( &apos;http&apos; =&gt; array( &apos;header&apos; =&gt; &quot;Content-Type: application/json
&quot;. &quot;Content-Length: &quot;.strlen($data).&quot;
&quot;. &quot;User-Agent:SteemMention/1.0
&quot;, &apos;method&apos; =&gt; &apos;POST&apos;, &apos;content&apos; =&gt; $data, ) ); $context = stream_context_create($options); try &#123; $result = file_get_contents($url, false, $context); $r = json_decode($result, true); $result = $r[&apos;result&apos;]; &#125; catch (\Exception $e) &#123; return false; &#125; return $result[&apos;total_vesting_fund_steem&apos;][&apos;amount&apos;] / ($result[&apos;total_vesting_shares&apos;][&apos;amount&apos;] / 1e6);&#125;function vests_to_sp($vests) &#123; $steem_per_mvests = steem_per_mvests(); if ($steem_per_mvests) &#123; return $vests / 1e6 * $steem_per_mvests; &#125; else &#123; return false; &#125;&#125;

注意：该文转载出处已不可访问，找到一篇相似的文章，可以参考：https://blog.csdn.net/liuchonge/article/details/50061331 – 2019-11-28 更新 转自：http://www.devdiv.com/chunked_httpc-article-2473-1.html 今天的主要内容还是不会偏离帖子的标题，关于HTTP采用chunked方式传输数据的解码问题。相信“在座”的各位有不少是搞过web系统的哈，但考虑到其他没接触过的XDJMs，这里还是简要的介绍一下： chunked编码的基本方法是将大块数据分解成多块小数据，每块都可以自指定长度，其具体格式RFC文档中是这样描述的(http://www.w3.org/Protocols/rfc2616/rfc2616-sec3.html)： 12345678910111213Chunked-Body = *chunk last-chunk trailer CRLFchunk = chunk-size [ chunk-extension ] CRLF chunk-data CRLFchunk-size = 1*HEXlast-chunk = 1*(&quot;0&quot;) [ chunk-extension ] CRLFchunk-extension= *( &quot;;&quot; chunk-ext-name [ &quot;=&quot; chunk-ext-val ] )chunk-ext-name = tokenchunk-ext-val = token | quoted-stringchunk-data = chunk-size(OCTET)trailer = *(entity-header CRLF) 这个据说是BNF文法，我本人有点陌生，于是又去维基百科里面找了下，里面有报文举例，这样就一目了然了(http://en.wikipedia.org/wiki/Chunked_transfer_encoding)，我摘一段报文如下： 123456789101112131415HTTP/1.1 200 OKContent-Type: text/plainTransfer-Encoding: chunked25This is the data in the first chunk1Cand this is the second one3con8sequence0 总而言之呢，就是说，这种方式的HTTP响应，头字段中不会带上我们常见的Content-Length字段，而是带上了Transfer-Encoding: chunked的字样。这种响应是未知长度的，有很多段自定义长度的块组合而成，每个块以一个十六进制数开头，该数字表示这块chunk数据的长度(包括数据段末尾的CRLF，但不包括十六进制数后面的CRLF)。 于是，众多Coders在发现了这个真相以后就开始在互联网上共享各种语言的解码代码。我看了C、PHP和Python那几个版本的代码，发现了一个问题就是，他们解析的数据是完整的，也就是说，他们所操纵的数据是假定已经在解码前在外部完成了拼装的，但是这完全不符合我的使用场景，Why？因为我的数据都是直接从Socket里面拿出来的，Socket里面的数据绝对不会有如此漂亮的格式，它们在那个时候都是散装的，当然我也可以选择将他们组装好然后再去解，但是以我粗浅的认识认为，那样子无论是从时间还是从空间的效率上来讲都是极为低下的(当你开发了一个kext程序，就明白我的苦衷了)。于是我又继续搜索，以期待能有高手已经提前帮我解决了这些问题，不过很遗憾，我没能找到。 没办法，自己做吧，比较重要的地方无非就是一个结尾的判断、一个chunk长度的读取、chunk之间的分段问题。看起来貌似比较轻松，不过代码写起来还是花费了不少时间的，今天又单独从项目中提取了这部分功能用C重写了一下。接下来就结合部分代码来说明一下整个过程。 先看dechunk.h这个文件 12345678910111213#define DCE_OK 0#define DCE_ISRUNNING 1#define DCE_FORMAT 2#define DCE_ARGUMENT 3#define DCE_MEM 4#define DCE_LOCK 5int dechunk_init();int dechunk(void *input, size_t inlen);int dechunk_getbuff(void **buff, size_t *buf_size);int dechunk_free();void *memstr(void *src, size_t src_len, char *sub); 宏定义就不用说了，都是一些错误码定义。函数一共有5个。dechunk_init、dechunk、dechunk_free这三个是解码的主要流程，dechunk_getbuff则是获取数据的接口。接下来看memstr，这是个很奇怪的名字，也是代码中唯一值得重点提醒一下的地方，其主要功能是在一块内存中寻找能匹配sub表示的字符串的地址。有人肯定要问了，不是有strstr么？对，我也这样想过，并且对于一些chunked网站也是实用的，但是，它不是通用的。主要是因为还有一些网站不仅使用了chunked传输方式，还采用了gzip的内容编码方式。当你碰到这种网站的时候，你再想使用strstr就等着郁闷吧，因为strstr会以字符串中的’\0’字符作为结尾标识，而恰巧经过gzip编码后的数据会有大量的这种字符。 接下来看dechunk.c123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102int dechunk(void *input, size_t inlen)&#123; if (!g_is_running) &#123; return DCE_LOCK; &#125; if (NULL == input || inlen &lt;= 0) &#123; return DCE_ARGUMENT; &#125; void *data_start = input; size_t data_len = inlen; if (g_is_first) &#123; data_start = memstr(data_start, data_len, &quot;

&quot;); if (NULL == data_start) &#123; return DCE_FORMAT; &#125; data_start += 4; data_len -= (data_start - input); g_is_first = 0; &#125; if (!g_is_chunkbegin) &#123; char *stmp = data_start; int itmp = 0; sscanf(stmp, &quot;%x&quot;, &amp;itmp;); itmp = (itmp &gt; 0 ? itmp - 2 : itmp); // exclude the terminate &quot;
&quot; data_start = memstr(stmp, data_len, &quot;
&quot;); data_start += 2; // strlen(&quot;
&quot;) data_len -= (data_start - (void *)stmp); g_chunk_len = itmp; g_buff_outlen += g_chunk_len; g_is_chunkbegin = 1; g_chunk_read = 0; if (g_chunk_len &gt; 0 &amp;&amp; 0 != g_buff_outlen) &#123; if (NULL == g_buff_out) &#123; g_buff_out = (char *)malloc(g_buff_outlen); g_buff_pt = g_buff_out; &#125; else &#123; g_buff_out = realloc(g_buff_out, g_buff_outlen); &#125; if (NULL == g_buff_out) &#123; return DCE_MEM; &#125; &#125; &#125;#define CHUNK_INIT() \do \&#123; \g_is_chunkbegin = 0; \g_chunk_len = 0; \g_chunk_read = 0; \&#125; while (0) if (g_chunk_read &lt; g_chunk_len) &#123; size_t cpsize = DC_MIN(g_chunk_len - g_chunk_read, data_len); memcpy(g_buff_pt, data_start, cpsize); g_buff_pt += cpsize; g_chunk_read += cpsize; data_len -= (cpsize + 2); data_start += (cpsize + 2); if (g_chunk_read &gt;= g_chunk_len) &#123; CHUNK_INIT(); if (data_len &gt; 0) &#123; return dechunk(data_start, data_len); &#125; &#125; &#125; else &#123; CHUNK_INIT(); &#125;#undef CHUNK_INIT() return DCE_OK;&#125; 其他函数没什么好说的，主要就只是把dechunk这个函数的流程讲一下(本来要是写了注释，我就不啰嗦这么多了，没办法，我们还是要对自己写的代码负责的不是)。 首先判断是否初始化过，全局变量g_is_running的唯一用途就只是用来防止多线程的调用，这只是一种很低级的保护，大家可以在实际使用中仁者见仁，智者见智。接下来，判断是否是http响应的第一个包，因为第一个包中包含有http的相应头，我们必须把这部分内容给过滤掉，判断的依据就是寻找两个连续的CRLF，也就是”

”。响应body的第一行，毫无疑问是第一个chunk的size字段，读取出来，设置状态，设置计数器，分配内存(如果不是第一个chunk的时候，通过realloc方法动态改变我们所分配的内存)。紧接着，就是一个对数据完整性的判断，如果input中的剩余数据的大小比我们还未读取到缓冲区中的chunk的size要小，这很明显说明了这个chunk分成了好几次被收到，那么我们直接按顺序拷贝到我们的chunk缓冲区中即可。反之，如果input中的剩余数据比未读取的size大，则说明了当前这个input数据包含了不止一个chunk，此时，使用了一个递归来保证把数据读取完。这里值得注意的一点是读取数据的时候要把表示数据结束的CRLF字符忽略掉。总的流程基本就是这个样子，外部调用者通过循环把socket获取到的数据丢进来dechunk，外部循环结束条件就是socket接受完数据或者判断到表示chunk结束的0数据chunk。 最后看一下main.c 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124125126127128129130131132int main (int argc, const char * argv[])&#123; const char *server_ipstr = &quot;59.151.32.20&quot;; // the host address of &quot;www.mtime.com&quot; // you can also use function gethostbyname // to get the address const unsigned short server_port = 80; // default port of http protocol int sock_http_get = -1; do &#123; sock_http_get = socket(PF_INET, SOCK_STREAM, 0); if (-1 == sock_http_get) &#123; printf(&quot;socket() error %d.
&quot;, errno); break; &#125; struct sockaddr_in addr_server; bzero(&amp;addr;_server, sizeof(addr_server)); addr_server.sin_family = AF_INET; addr_server.sin_addr.s_addr = inet_addr(server_ipstr); addr_server.sin_port = htons(server_port); if (-1 == connect(sock_http_get, (struct sockaddr *)&amp;addr;_server, sizeof(addr_server))) &#123; printf(&quot;connect() error %d.
&quot;, errno); break; &#125; printf(&quot;connected...
&quot;); char *request = &quot;GET / HTTP/1.1
&quot; &quot;Host: www.mtime.com
&quot; &quot;Connection: keep-alive
&quot; &quot;User-Agent: Mozilla/5.0 (Macintosh; Intel Mac OS X 10_6_8) AppleWebKit/535.1 (KHTML, like Gecko) Chrome/13.0.782.220 Safari/535.1
&quot; &quot;Accept: text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8
&quot; &quot;Accept-Encoding: gzip,deflate,sdch
&quot; &quot;Accept-Language: zh-CN,zh;q=0.8
&quot; &quot;Accept-Charset: GBK,utf-8;q=0.7,*;q=0.3
&quot; &quot;Cookie: DefaultCity-CookieKey=561; DefaultDistrict-CookieKey=0; _userCode_=2011725182104293; _userIdentity_=2011725182109188; _movies_=105799.87871.91873.68867; __utma=196937584.1484842614.1299113024.1314613017.1315205344.4; __utmz=196937584.1299113024.1.1.utmcsr=(direct)|utmccn=(direct)|utmcmd=(none); _urm=0%7C0%7C0%7C0%7C0; _urmt=Mon%2C%2005%20Sep%202011%2006%3A49%3A04%20GMT
&quot; &quot;
&quot;; if (-1 == send(sock_http_get, request, strlen(request), 0)) &#123; printf(&quot;send() error %d.
&quot;, errno); break; &#125;#define MY_BUF_SIZE 1024 char buff[MY_BUF_SIZE] = &#123;0&#125;; int recv_bytes = 0; int chunkret = DCE_OK; if (DCE_OK == dechunk_init()) &#123; while (-1 != (recv_bytes = recv(sock_http_get, buff, MY_BUF_SIZE, 0)) &amp;&amp; 0 != recv_bytes) &#123; printf(&quot;%s&quot;, buff); if (DCE_OK != (chunkret = dechunk(buff, recv_bytes))) &#123; printf(&quot;
chunkret = %d
&quot;, chunkret); break; &#125; if (NULL != memstr(buff, recv_bytes, &quot;
0
&quot;)) &#123; break; &#125; bzero(buff, MY_BUF_SIZE); &#125; printf(&quot;
*********************************
&quot;); printf(&quot;receive finished.
&quot;); printf(&quot;*********************************
&quot;); void *zipbuf = NULL; size_t zipsize = 0; dechunk_getbuff(&amp;zipbuf;, &amp;zipsize;); printf(&quot;
%s
&quot;, (char *)zipbuf); z_stream strm; bzero(&amp;strm;, sizeof(strm)); printf(&quot;BEGIN:decompress...
&quot;); printf(&quot;*********************************
&quot;); if (Z_OK == inflateInit2(&amp;strm;, 31)) // 31:decompress gzip &#123; strm.next_in = zipbuf; strm.avail_in = zipsize; char zbuff[MY_BUF_SIZE] = &#123;0&#125;; do &#123; bzero(zbuff, MY_BUF_SIZE); strm.next_out = (Bytef *)zbuff; strm.avail_out = MY_BUF_SIZE; int zlibret = inflate(&amp;strm;, Z_NO_FLUSH); if (zlibret != Z_OK &amp;&amp; zlibret != Z_STREAM_END) &#123; printf(&quot;
inflate ret = %d
&quot;, zlibret); break; &#125; printf(&quot;%s&quot;, zbuff); &#125; while (strm.avail_out == 0); &#125; printf(&quot;
&quot;); printf(&quot;*********************************
&quot;); dechunk_free(); &#125;#undef MY_BUF_SIZE &#125; while (0); close(sock_http_get); return 0;&#125; 按照惯例，main函数是我们用来测试的函数。 这个函数中，我们首先使用socket创建了跟服务器之间的连接，紧接着我手动构造了一个请求报文，通过socket发送出去，然后循环获取数据。然后通过使用zlib库来对dechunk出来的数据进行解码以确定数据是否正确。关于zlib的使用跟本次讨论的话题不太沾边，这里就不详述，有兴趣的我们可以另行讨论。 解码前和解码后的数据都会被打印到控制台中去，日志比较庞大，这里就不给出具体信息了，大家可以自行调试观察。关于这个文件我说明一下，网站选的是www.mtime.com，因为它采用的就是chunked + gzip的方式，是一种相对难处理的数据。该网站的IP地址信息，相信各位有不下于100种方法去找到，所以我就没有使用gethostbyname那个方法了，因为那个方法返回的结构体使用起来实在不怎么方便。另外就是关于手动拼装的请求报文哪里来，千万不要告诉我你去用各种专业抓包工具去抓。没那么麻烦，打开你的Chrome，右键选择审查元素，然后访问你要访问的网站，OK，所有请求都会被记录在案。 /*分割一下吧*/ 关于代码就说这么多，不过我还是声明一下，因为没多少时间，所以我只能尽力把代码写的不那么难看，注释不多，但我在这里也有所弥补，各个函数功能的实现也许有效率方面的问题抑或是各种bug，这个属于我的编程能力不足，大家可以提出宝贵的修改意见，我一定虚心接受。如果有不明白的地方(我这只是以防万一哈^_^)也可以跟帖一起讨论。根据设计的原则，每个函数的功能应该尽量的单一和完整，调用者应该确保传递的数据符合函数的要求，但是我的main函数中却没有一些必要的判断(比如http响应是否是chunked的，是否是gzip的)，因为我准备的测试数据已经确定好了的。 写了那么多，也该结尾了，不过还是要送上源码工程以祝大家天天晚上睡好觉！源码在这里 —&gt;Vincent，如果您要查看本帖隐藏内容请回复 doors.du说：“我觉得明天起床这个帖子会火的，不管你们信不信，我反正信了……” http_chunk_demo.zip (19.35 KB, 下载次数: 2742)

今天在写程序的时候，发现运算浮点数的时候，总是带着一串随机的小数尾巴，查资料知道，浮点数不能做精确计算，如果要是做精确计算，需要用decimal类型的字段，而不是单精或者双精。 附：http://my.oschina.net/miaoyushun/blog/12684 对于这个问题的发现源于一个计时器程序，先看下这段代码吧。 123456789101112&lt;?php$s = gettime();usleep(10000);$e = gettime();var_dump($s);var_dump($e);echo $e-$s.&quot;
&quot;;function gettime()&#123; list($sec, $uses) = explode(&apos; &apos;, microtime()); return $sec + $usec;&#125;?&gt; 输出结果为： 123float(1296098836.2033)float(1296098836.2135)0.010126113891602 有没有发现一个很诡异的现象？被减数和减数整数部分是相同的，小数点后都只是四位，但是这两个数相减之后得出的结果，小数点后的位数却要大于4。其实想解释也不难，因为被减数和减数的精度都为14，所以为不造成精度损失，所以结果的精度也必须是14位的。 但出现这种现象的根本原因在哪？ 所以我去网上逛了逛，看了些东西后，得到了一些启发。所以又写了一段测试代码： 12345678&lt;?phpini_set(&apos;precision&apos;, 14);$a = 0.3;$b = 0.1+0.2;var_dump($a);var_dump($b);$a == $b ? print &quot;equals
&quot; : print &quot;not equals
&quot;;?&gt; 输出的结果是： 123float(0.3);float(0.3);not equals 大家是不是感觉很奇怪，两个变量都是浮点型的，都是0.3，为什么不相等呢？ 使用序列化函数serialize查看一下两个数的实际值： 1234&lt;?phpecho serialize(0.3).&quot;
&quot;;echo serialize(0.1+0.2).&quot;
&quot;;?&gt; 输出结果： 12d:0.299999999999999988897769753748434595763683319091796875;d:0.3000000000000000444089209850062616169452667236328125; 你会发现这两个数实际上都不是真正的0.3，为什么这样呢？ 其实这个问题要追溯到微机原理（也有可能是计算机组成原理，记不清楚是哪一本书了），这里面讲了计算机是如何用二进制来存储定点小数。大致是这样的：如果用一个字节的长度来表示一个定点小数，第一位表示小数的符号，0为正，1为负；后面7位表示小数的值，第2位至第8位的位权分别是1/2,1/4,1/8,1/16,1/32,1/64,1/128，然后用这些权值的和来表示所有的小数。如何表示0.625呢？ 这个有固定的算法： 首先，将小数点左侧的整数部分变换为其二进制形式，处理小数部分的算法是将我们的小数部分乘以基数 2，记录乘积结果的整数部分，接着将结果的小数部分继续乘以 2，并不断继续该过程。 1230.625 × 2 = 1.25 10.25 × 2 = 0.5 00.5 × 2 = 1 1 当最后的结果为1时，结束这个过程。这时右侧的一列数字就是我们所需的二进制小数部分，即 0.101。这样，我们就得到了完整的二进制形式 0.101 ，按阶展开：1x1/2+0x1/4+1x1/8=0.5+0.125=0.625。 我们上面先的例子比较特殊，这个数只需要三次运算就能够结束。那会不会有无法结束的情况，不难想象，很多小数根本不能经过有限次这样的过程而得到结 果（比如最简单的0.1）。 但浮点数尾数域的位数是有限的，为此，浮点数的处理办法是持续该过程直到由此得到的尾数足以填满尾数域，之后对多余的位进行舍入。也就是说，十进制到二进制的变换也并不能保证总是精确的，而只能是近似值。 事实上，只有很少一部分十进制小数具有精确的二进制浮点数表达。再加上浮点数运算过程中的误差累积，结果是很多我们看来非常简单的十进制运算在计算机上却往往出人意料。这就是最常见的浮点运算的”不准确”问题。 所以，在计算机里表示的浮点数只是一个近似的数，并不是像表示整数那样精确没有偏差。既然它只是一个约数，那么你用精确的==来比较两位不精确的约数就没有太大意义了。如果一定要比较两个浮点数，可以考虑先转换成字符串，然后再去比较。 我在Linux下使用c编写了一段类似的浮点数比较的代码，结果也是不相等的。实际上在所有的语言里都会存在此问题，因为这是计算机原理所决定的。但也不排除一些语言做了些后期处理，可以直接比较两个浮点数。 以上仅是个人理解，不保证绝对正确，有错误还请多多谅解。

数组的声明规则：（1）数组的名称由一个美元符号开始，第一个字符是字母或下划线，其后是任意数量的字幕，数字或下划线。（2）在同一个程序中，标量变量和数组变量都不能重名。（3）数组的名称区别大小写。 通过标示符[]可以直接为数组元素复制，格式如下：$array_name[key]=value;或者$array_name[]=value; 应用array()函数创建数组，语法如下：array array([mixed…])参数mixed的语法为“key=&gt;value”，多个参数mixed用逗号分开，分别定义了索引（key）和值（value）。应用array函数声明数组时，数组下标既可以是数值索引也可以是关联索引。 示例： 123456789101112&lt;?php $arr1=array(&apos;PHP&apos;=&gt;&apos;php&apos;,&apos;JAVA&apos;=&gt;&apos;java&apos;); //以字符串作为数组索引，指定关键字，关联数组 print_r($arr1); echo &quot;
&quot;.$arr1[&apos;JAVA&apos;].&quot;
&quot;; $arr2=array(&apos;PHP&apos;,&apos;Java&apos;); //以数字作为数组索引，从0开始，没有指定关键字，数字索引数组 print_r($arr2); echo &quot;
&quot;.$arr2[&apos;0&apos;].&quot;
&quot;; $arr3=array(0=&gt;&apos;PHP&apos;,1=&gt;&apos;Java&apos;,1=&gt;&apos;domyself.me&apos;); //指定相同的索引，后一个将会覆盖之前的值 print_r($arr3);?&gt; 1234567891011121314151617181920运行结果：Array( [PHP] =&gt; php [JAVA] =&gt; java)javaArray( [0] =&gt; PHP [1] =&gt; Java)PHPArray( [0] =&gt; PHP [1] =&gt; domyself.me) 遍历数组有三种方法：（1）用foreach遍历数组（2）用list()和each()遍历数组示例： 123456&lt;?php $arr=array(0=&gt;&apos;PHP&apos;,1=&gt;&apos;VB&apos;,2=&gt;&apos;Java&apos;,3=&gt;&apos;VC&apos;); while(list($key,$val)=each($arr))&#123; echo &quot;$key=$val
&quot;; &#125;?&gt; 说明：each()返回数组中当前指针指向位置的键名和对应的值，然后移动指针到下一个位置，返回值就是4个元素的关联数组，通过list()语言结构赋给指定的值。 （3）用for和count()来遍历数组count($arr)的意思就是$arr的上界。 输出数组两种方法，一种是直接使用print_f()，一种是使用echo语句。前者可以把数组全部输出，包括结构，后者只能输出指定的数组项，还需要借助循环才能全部输出数组。 数组函数（1）count()统计数组元素个数（2）向数组添加元素，array_push()把数组当成一个栈，将传入的变量压入该数组的末尾。语法如下：int array_push(array array,mixed var[,mixed…])参数array为指定的数组，参数var是压入数组中的值。建议：使用[]给数组添加元素。（3）获取数组中最后一个元素，同样是把数组当作了栈，函数是：array_pop()。（4）删除数组中重复元素，array_unique()（5）获取数组中指定元素的键名，array_search()，语法如下：mixed array_search(mixed needle,array haystack[,bool strict])参数needle指定在数组中搜索的值，如果needle是字符串，则在搜索needle的值时是区分字符串的大小写的。参数haystack指定被搜索的数组。参数strict为可选参数，如果值为true，还将在haystack中检查needle的类型。（该函数区分大小写）注意：使用array_search()函数查询数组中的指定元素时，如果查询的元素在数组中多次出现，那么该函数只返回第一个匹配的键名，如果想返回所有的，用array_keys()。 1234567补充：其他的创建数组的方法array_combine()===以一个数组为关键字，另一个数组为值创建新数组array_fill()===用值填充一个数组array_pad()===用一个值把数组填充到指定长度compact()===创建包含变量及其值的数组range()===创建一个包含一定范围内的元素的数组

对于图的深度遍历相信学过数据结构的人都不会陌生吧，有时间，所以写了个图的深度遍历源代码，拿出来给大家分享一下。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596#include &lt;stdio.h&gt;#include &lt;malloc.h&gt;#define INFINITY 32767#define MAX_VEX 20 //最大顶点个数bool *visited; //访问标志数组//图的邻接矩阵存储结构typedef struct&#123; char *vexs; //顶点向量 int arcs[MAX_VEX][MAX_VEX]; //邻接矩阵 int vexnum,arcnum; //图的当前顶点数和弧数&#125;Graph;//图G中&lt;!-- more --&gt;查找元素c的位置int Locate(Graph G,char c)&#123; for(int i=0;i&lt;G.vexnum;i++) if(G.vexs[i]==c) return i; return -1;&#125;//创建无向网void CreateUDN(Graph &amp;G)&#123; int i,j,w,s1,s2; char a,b,temp; printf(&quot;输入顶点数和弧数:&quot;); scanf(&quot;%d%d&quot;,&amp;G.vexnum,&amp;G.arcnum); temp=getchar(); //接收回车 G.vexs=(char *)malloc(G.vexnum*sizeof(char)); //分配顶点数目 printf(&quot;输入%d个顶点.
&quot;,G.vexnum); for(i=0;i&lt;G.vexnum;i++)&#123; //初始化顶点 printf(&quot;输入顶点%d:&quot;,i); scanf(&quot;%c&quot;,&amp;G.vexs[i]); temp=getchar(); //接收回车 &#125; for(i=0;i&lt;G.vexnum;i++) //初始化邻接矩阵 for(j=0;j&lt;G.vexnum;j++) G.arcs[i][j]=INFINITY; printf(&quot;输入%d条弧.
&quot;,G.arcnum); for(i=0;i&lt;G.arcnum;i++)&#123; //初始化弧 printf(&quot;输入弧%d:&quot;,i); scanf(&quot;%c %c %d&quot;,&amp;a,&amp;b,&amp;w); //输入一条边依附的顶点和权值 temp=getchar(); //接收回车 s1=Locate(G,a); s2=Locate(G,b); G.arcs[s1][s2]=G.arcs[s2][s1]=w; &#125;&#125;//图G中顶点k的第一个邻接顶点int FirstVex(Graph G,int k)&#123; if(k&gt;=0 &amp;&amp; k&lt;G.vexnum)&#123; //k合理 for(int i=0;i&lt;G.vexnum;i++) if(G.arcs[k][i]!=INFINITY) return i; &#125; return -1;&#125;//图G中顶点i的第j个邻接顶点的下一个邻接顶点int NextVex(Graph G,int i,int j)&#123; if(i&gt;=0 &amp;&amp; i&lt;G.vexnum &amp;&amp; j&gt;=0 &amp;&amp; j&lt;G.vexnum)&#123; //i,j合理 for(int k=j+1;k&lt;G.vexnum;k++) if(G.arcs[i][k]!=INFINITY) return k; &#125; return -1;&#125;//深度优先遍历void DFS(Graph G,int k)&#123; int i; if(k==-1)&#123; //第一次执行DFS时,k为-1 for(i=0;i&lt;G.vexnum;i++) if(!visited[i]) DFS(G,i); //对尚未访问的顶点调用DFS &#125; else&#123; visited[k]=true; printf(&quot;%c &quot;,G.vexs[k]); //访问第k个顶点 for(i=FirstVex(G,k);i&gt;=0;i=NextVex(G,k,i)) if(!visited[i]) DFS(G,i); //对k的尚未访问的邻接顶点i递归调用DFS &#125;&#125;//主函数void main()&#123; int i; Graph G; CreateUDN(G); visited=(bool *)malloc(G.vexnum*sizeof(bool)); printf(&quot;
深度优先遍历: &quot;); for(i=0;i&lt;G.vexnum;i++) visited[i]=false; DFS(G,-1); printf(&quot;
程序结束.
&quot;);&#125; 输出结果为（红色为键盘输入的数据，权值都置为1）： 12345678910111213141516171819202122232425262728293031323334353637383940414243输入顶点数和弧数:8 9输入8个顶点.输入顶点0:a输入顶点1:b输入顶点2:c输入顶点3:d输入顶点4:e输入顶点5:f输入顶点6:g输入顶点7:h输入9条弧.输入弧0:a b 1输入弧1:b d 1输入弧2:b e 1输入弧3:d h 1输入弧4:e h 1输入弧5:a c 1输入弧6:c f 1输入弧7:c g 1输入弧8:f g 1深度优先遍历: a b d h e c f g 程序结束.
